+    // --- Two-sided wall (upper/lower portal) ---
+
+    /// Build a two-room map connected by a two-sided linedef where the back
+    /// sector has a higher floor and lower ceiling than the front, so both
+    /// upper and lower wall portions are drawn.
+    fn make_two_room_map() -> DoomMap {
+        use super::super::map::*;
+        // Two sectors sharing a wall at y=128.
+        // Front sector: floor=0, ceiling=128
+        // Back sector:  floor=32, ceiling=96  (step up + lower ceiling)
+        let vertices = vec![
+            Vertex { x: 0.0, y: 0.0 },     // 0 — bottom-left front
+            Vertex { x: 256.0, y: 0.0 },   // 1 — bottom-right front
+            Vertex { x: 256.0, y: 128.0 }, // 2 — top-right front / bottom-right back
+            Vertex { x: 0.0, y: 128.0 },   // 3 — top-left front / bottom-left back
+            Vertex { x: 256.0, y: 256.0 }, // 4 — top-right back
+            Vertex { x: 0.0, y: 256.0 },   // 5 — top-left back
+        ];
+        let sectors = vec![
+            Sector {
+                floor_height: 0.0,
+                ceiling_height: 128.0,
+                floor_texture: "FLOOR".into(),
+                ceiling_texture: "CEIL".into(),
+                light_level: 200,
+                special: 0,
+                tag: 0,
+            },
+            Sector {
+                floor_height: 32.0,
+                ceiling_height: 96.0,
+                floor_texture: "FLOOR2".into(),
+                ceiling_texture: "CEIL2".into(),
+                light_level: 160,
+                special: 0,
+                tag: 0,
+            },
+        ];
+        let sidedefs = vec![
+            // sidedef 0: front sector walls
+            SideDef {
+                x_offset: 0.0,
+                y_offset: 0.0,
+                upper_texture: "-".into(),
+                lower_texture: "-".into(),
+                middle_texture: "WALL".into(),
+                sector: 0,
+            },
+            // sidedef 1: two-sided front side (facing front sector)
+            SideDef {
+                x_offset: 0.0,
+                y_offset: 0.0,
+                upper_texture: "UPPER".into(),
+                lower_texture: "LOWER".into(),
+                middle_texture: "-".into(),
+                sector: 0,
+            },
+            // sidedef 2: two-sided back side (facing back sector)
+            SideDef {
+                x_offset: 0.0,
+                y_offset: 0.0,
+                upper_texture: "UPPER".into(),
+                lower_texture: "LOWER".into(),
+                middle_texture: "-".into(),
+                sector: 1,
+            },
+            // sidedef 3: back sector outer walls
+            SideDef {
+                x_offset: 0.0,
+                y_offset: 0.0,
+                upper_texture: "-".into(),
+                lower_texture: "-".into(),
+                middle_texture: "WALL2".into(),
+                sector: 1,
+            },
+        ];
+        let linedefs = vec![
+            // Front room walls (one-sided)
+            LineDef {
+                v1: 0,
+                v2: 1,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(0),
+                back_sidedef: None,
+            },
+            LineDef {
+                v1: 1,
+                v2: 2,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(0),
+                back_sidedef: None,
+            },
+            LineDef {
+                v1: 3,
+                v2: 0,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(0),
+                back_sidedef: None,
+            },
+            // Two-sided portal wall between rooms (v3→v2)
+            LineDef {
+                v1: 3,
+                v2: 2,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(1),
+                back_sidedef: Some(2),
+            },
+            // Back room walls (one-sided)
+            LineDef {
+                v1: 2,
+                v2: 4,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(3),
+                back_sidedef: None,
+            },
+            LineDef {
+                v1: 4,
+                v2: 5,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(3),
+                back_sidedef: None,
+            },
+            LineDef {
+                v1: 5,
+                v2: 3,
+                flags: 0,
+                special: 0,
+                tag: 0,
+                front_sidedef: Some(3),
+                back_sidedef: None,
+            },
+        ];
+        let segs = vec![
+            // Front room segs
+            Seg {
+                v1: 0,
+                v2: 1,
+                angle: 0.0,
+                linedef: 0,
+                direction: 0,
+                offset: 0.0,
+            },
+            Seg {
+                v1: 1,
+                v2: 2,
+                angle: 0.0,
+                linedef: 1,
+                direction: 0,
+                offset: 0.0,
+            },
+            Seg {
+                v1: 3,
+                v2: 0,
+                angle: 0.0,
+                linedef: 2,
+                direction: 0,
+                offset: 0.0,
+            },
+            // Two-sided seg (portal)
+            Seg {
+                v1: 3,
+                v2: 2,
+                angle: 0.0,
+                linedef: 3,
+                direction: 0,
+                offset: 0.0,
+            },
+            // Back room segs
+            Seg {
+                v1: 2,
+                v2: 4,
+                angle: 0.0,
+                linedef: 4,
+                direction: 0,
+                offset: 0.0,
+            },
+            Seg {
+                v1: 4,
+                v2: 5,
+                angle: 0.0,
+                linedef: 5,
+                direction: 0,
+                offset: 0.0,
+            },
+            Seg {
+                v1: 5,
+                v2: 3,
+                angle: 0.0,
+                linedef: 6,
+                direction: 0,
+                offset: 0.0,
+            },
+        ];
+        // Two subsectors: front room (segs 0..3) and back room (segs 4..6).
+        // With an empty nodes vec the BSP traversal processes subsectors
+        // in order, which is fine for this test.
+        let subsectors = vec![
+            SubSector {
+                num_segs: 4,
+                first_seg: 0,
+            },
+            SubSector {
+                num_segs: 3,
+                first_seg: 4,
+            },
+        ];
+        DoomMap {
+            name: "TWOROOM".into(),
+            vertices,
+            linedefs,
+            sidedefs,
+            sectors,
+            segs,
+            subsectors,
+            nodes: vec![],
+            things: vec![],
+        }
+    }
